var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"휴우, 추워. 여긴 뭐가 이렇게 쏟아지는 걸까요? 잿가루?","JPN":"うう、寒い。これ、何が降ってるんですか？　灰？","ENG":"Whew, it's cold. What's all that coming down from the sky? Ashes?","TWN":"呼，好冷。這裡下的是什麼東西？是灰嗎？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"눈이란 것이다. 사계가 존재하던 때엔 동절기가 오면 비를 대신해 내리곤 했지.","JPN":"雪というものだ。四季が存在していたころ、冬になると雨の代わりに降っていた。","ENG":"It is called snow. When there were four seasons, snow would replace rain in the winter.","TWN":"這就是雪。在四季分明的過去，冬天會下雪 。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"신기하네요. 밟으면 뽀스락거리고 제 발자국도 남아요.","JPN":"不思議ですね。踏むとサクサクしていて、足跡も残るんですね。","ENG":"It's amusing. It makes a squishy sound, and I can see my footprints too.","TWN":"好神奇啊。踩上去會發出沙沙響，還會留下腳印。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"무얼 하는 거지?","JPN":"何をしている？","ENG":"What are you doing?","TWN":"你在做什麼？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"잠시만요.","JPN":"ちょっと待ってくださいね。","ENG":"Just a moment.","TWN":"等我一下。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"짜안-","JPN":"ジャーン！","ENG":"Ta-da!","TWN":"鏘鏘——"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"눈인형을 만들어봤어요.","JPN":"雪だるまを作ってみました。","ENG":"I made a snow doll.","TWN":"我做了個雪人。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"인형…?","JPN":"雪だるま……？","ENG":"Snow doll...?","TWN":"雪人……？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"덩어리를 뭉쳐서 구멍으로 눈코입을 만든 것뿐이지만요.","JPN":"丸い塊を作って、穴で目と鼻と口を作っただけですけど。","ENG":"I just made it into a ball and poked holes in it to make a face.","TWN":"我把雪堆成球狀後，挖了洞做成了眼耳鼻。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"단순하지만, 제법 앙증맞게 생겼군. 손재주가 좋구나.","JPN":"単純だが、なかなか可愛らしいな。手先が器用だ。","ENG":"Simple, but endearing. You are good with your hands.","TWN":"雖然很簡單，但確實很可愛。好手藝。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"헤헤, 일을 나간 언니가 돌아올 때까지 저는 흙으로 인형을 만들면서 놀곤 했거든요.","JPN":"へへ、仕事に行ったお姉さんが帰って来るまで、土で人形を作りながら遊んでたんです。","ENG":"Heh heh, I used to make dolls out of mud while my sister was out for work.","TWN":"嘿嘿，在以前姊姊出去工作後，我就經常一個人用泥土捏成人偶玩，等待姊姊回來。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"진짜 인형은 아니긴 하지만… 나중에 돈벌면 진짜 재료를 사서 연습할 거예요!","JPN":"本物の人形じゃないですけど……大きくなってお金を稼いだら、材料を買って練習します！","ENG":"It's not a real doll, but... when I get a job, I'm going to buy the proper materials and start practicing!","TWN":"雖然不是真正的娃娃……但以後我賺夠了錢，我會買真材實料來練習！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너의 누이는… 약초를 찾으러 떠났다가 돌아오지 않았다고 했지.","JPN":"そなたの姉は……薬草探しに家を出たきり、帰ってこなかったと言っていたな。","ENG":"You had mentioned... that your sister never returned after departing on a quest for herbs.","TWN":"你姊姊……聽你說在出去採集草藥後，就再也沒回來。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"흰 서리꽃. 그게 있어야 제 병이 낫는다고 했어요.","JPN":"白い霜の花。それがないと私の病気が治らないって。","ENG":"The white frost flowers. She said she needed those to cure my illness.","TWN":"白色的霜花，她說只有那種花才能治好我的病。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"그때 언니를 혼자 보내지 말 걸… 언니를 찾는 지금도 계속 후회하고 있어요.","JPN":"あの時お姉さんを一人で行かせるべきじゃなかった……今でもずっと後悔しています。","ENG":"I shouldn't have let her go alone... I regret making that choice, the more I search for her.","TWN":"我真不應該讓她一個人走……直到現在也在後悔。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너는 태양문 바깥의 설원에서 며칠씩이나 홀로 살아남았다.","JPN":"そなたは太陽の門の外にある雪原で、何日も一人で生き残った。","ENG":"You were alone on the snow-covered fields beyond the Solar Gates. And yet, you survived.","TWN":"你曾在太陽門外的雪地裡獨自生存了數日。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"나와 만났을 때도 마물들과 대등하게 맞서 싸우고 있었지.","JPN":"我と出会った時にも、魔物と対等に立ち向かい、戦っていた。","ENG":"You were neck and neck in your fight against those monsters when I encountered you.","TWN":"我們相遇的時候，你也在和怪物們勢均力敵地戰鬥。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};